INSERT INTO translations (namespace, key, locale, value, is_reviewed, version, created_at, updated_at) VALUES ('ui', 'landingPage.seoSection.article1.desc', 'en', 'Tired of getting off a tour bus, snapping one photo, and getting back on? Tourgether lets you experience hidden gems only locals know, authentic restaurants, and the real vibe of each city. Connect directly with local guides and plan your own customized journey.', false, 1, NOW(), NOW());
INSERT INTO translations (namespace, key, locale, value, is_reviewed, version, created_at, updated_at) VALUES ('ui', 'landingPage.seoSection.article1.desc', 'es', '¿Cansado de bajar del autobús turístico, tomar una foto y volver a subir? Tourgether te permite experimentar joyas ocultas que solo los locales conocen, restaurantes auténticos y la verdadera atmósfera de cada ciudad. Conéctate directamente con guías locales y planifica tu propio viaje personalizado.', false, 1, NOW(), NOW());
INSERT INTO translations (namespace, key, locale, value, is_reviewed, version, created_at, updated_at) VALUES ('ui', 'landingPage.seoSection.article1.desc', 'fr', 'Fatigué de descendre du bus touristique, de prendre une photo et de remonter ? Tourgether vous permet de découvrir des endroits cachés que seuls les locaux connaissent, des restaurants authentiques et la vraie atmosphère de chaque ville. Connectez-vous directement avec des guides locaux et planifiez votre propre voyage sur mesure.', false, 1, NOW(), NOW());
INSERT INTO translations (namespace, key, locale, value, is_reviewed, version, created_at, updated_at) VALUES ('ui', 'landingPage.seoSection.article1.desc', 'ja', '大型観光バスから降りて写真を1枚撮ってまたバスに乗る旅行に疲れていませんか？Tourgetherでは、地元の人だけが知る穴場スポット、ローカルグルメ、本当のその街の雰囲気を体験できます。現地ガイドと直接つながり、自分だけのオーダーメイド旅行を計画しましょう。', false, 1, NOW(), NOW());
INSERT INTO translations (namespace, key, locale, value, is_reviewed, version, created_at, updated_at) VALUES ('ui', 'landingPage.seoSection.article1.desc', 'ko', '대형 관광버스에서 내려 사진 한 장 찍고 다시 버스에 오르는 여행에 지치셨나요? Tourgether는 현지인만 아는 숨은 명소, 로컬 맛집, 진짜 그 도시의 분위기를 경험할 수 있게 해드립니다. 현지 가이드와 직접 연결되어 나만의 맞춤 여행을 계획하세요.', false, 1, NOW(), NOW());
INSERT INTO translations (namespace, key, locale, value, is_reviewed, version, created_at, updated_at) VALUES ('ui', 'landingPage.seoSection.article1.desc', 'zh', '厌倦了从大巴下来拍一张照片又上车的旅行吗？Tourgether让您体验只有当地人才知道的隐藏景点、地道美食和真正的城市氛围。直接与当地导游联系，规划属于您的定制旅行。', false, 1, NOW(), NOW());
INSERT INTO translations (namespace, key, locale, value, is_reviewed, version, created_at, updated_at) VALUES ('ui', 'landingPage.seoSection.article1.title', 'en', 'Say goodbye to cookie-cutter package tours', false, 1, NOW(), NOW());
INSERT INTO translations (namespace, key, locale, value, is_reviewed, version, created_at, updated_at) VALUES ('ui', 'landingPage.seoSection.article1.title', 'es', 'Dile adiós a los tours empaquetados aburridos', false, 1, NOW(), NOW());
INSERT INTO translations (namespace, key, locale, value, is_reviewed, version, created_at, updated_at) VALUES ('ui', 'landingPage.seoSection.article1.title', 'fr', 'Dites adieu aux voyages organisés monotones', false, 1, NOW(), NOW());
INSERT INTO translations (namespace, key, locale, value, is_reviewed, version, created_at, updated_at) VALUES ('ui', 'landingPage.seoSection.article1.title', 'ja', 'パッケージツアーの物足りなさを解決します', false, 1, NOW(), NOW());
INSERT INTO translations (namespace, key, locale, value, is_reviewed, version, created_at, updated_at) VALUES ('ui', 'landingPage.seoSection.article1.title', 'ko', '패키지 여행의 아쉬움을 해결합니다', false, 1, NOW(), NOW());
INSERT INTO translations (namespace, key, locale, value, is_reviewed, version, created_at, updated_at) VALUES ('ui', 'landingPage.seoSection.article1.title', 'zh', '告别千篇一律的跟团游', false, 1, NOW(), NOW());
INSERT INTO translations (namespace, key, locale, value, is_reviewed, version, created_at, updated_at) VALUES ('ui', 'landingPage.seoSection.article2.desc', 'en', 'Want to travel solo but worried about eating alone or having no one to take your photos? Use our "Open to Meet" feature to find other travelers in the same area. Share meals, tours, and activities with like-minded people and say goodbye to the loneliness of solo travel.', false, 1, NOW(), NOW());
INSERT INTO translations (namespace, key, locale, value, is_reviewed, version, created_at, updated_at) VALUES ('ui', 'landingPage.seoSection.article2.desc', 'es', '¿Quieres viajar solo pero te preocupa comer solo o no tener a nadie que te tome fotos? Usa nuestra función "Open to Meet" para encontrar otros viajeros en la misma zona. Comparte comidas, tours y actividades con personas afines y despídete de la soledad del viaje en solitario.', false, 1, NOW(), NOW());
INSERT INTO translations (namespace, key, locale, value, is_reviewed, version, created_at, updated_at) VALUES ('ui', 'landingPage.seoSection.article2.desc', 'fr', 'Envie de voyager seul mais inquiet de manger seul ou de n''avoir personne pour prendre vos photos ? Utilisez notre fonction "Open to Meet" pour rencontrer d''autres voyageurs dans la même région. Partagez repas, visites et activités avec des personnes partageant les mêmes intérêts.', false, 1, NOW(), NOW());
INSERT INTO translations (namespace, key, locale, value, is_reviewed, version, created_at, updated_at) VALUES ('ui', 'landingPage.seoSection.article2.desc', 'ja', '一人旅をしたいけど、一人でご飯を食べるのが不安だったり、写真を撮ってくれる人がいなくて残念だった経験はありませんか？「Open to Meet」機能で同じ地域にいる他の旅行者と出会いましょう。趣味が合う人たちと一緒の食事、ツアー、アクティビティで一人旅の寂しさを解消します。', false, 1, NOW(), NOW());
INSERT INTO translations (namespace, key, locale, value, is_reviewed, version, created_at, updated_at) VALUES ('ui', 'landingPage.seoSection.article2.desc', 'ko', '혼자 여행하고 싶지만 혼밥이 두렵거나, 사진 찍어줄 사람이 없어 아쉬웠던 경험이 있으신가요? "Open to Meet" 기능으로 같은 지역에 있는 다른 여행자들을 만나보세요. 취향이 맞는 사람들과 함께하는 식사, 투어, 액티비티로 혼자 여행의 외로움을 채워드립니다.', false, 1, NOW(), NOW());
INSERT INTO translations (namespace, key, locale, value, is_reviewed, version, created_at, updated_at) VALUES ('ui', 'landingPage.seoSection.article2.desc', 'zh', '想独自旅行但担心一个人吃饭，或者没人帮您拍照？使用"Open to Meet"功能，在同一地区找到其他旅行者。与志同道合的人一起用餐、旅游和活动，告别独行的孤独。', false, 1, NOW(), NOW());
INSERT INTO translations (namespace, key, locale, value, is_reviewed, version, created_at, updated_at) VALUES ('ui', 'landingPage.seoSection.article2.title', 'en', 'A connection platform for solo travelers', false, 1, NOW(), NOW());
INSERT INTO translations (namespace, key, locale, value, is_reviewed, version, created_at, updated_at) VALUES ('ui', 'landingPage.seoSection.article2.title', 'es', 'Una plataforma de conexión para viajeros solitarios', false, 1, NOW(), NOW());
INSERT INTO translations (namespace, key, locale, value, is_reviewed, version, created_at, updated_at) VALUES ('ui', 'landingPage.seoSection.article2.title', 'fr', 'Une plateforme de connexion pour les voyageurs solo', false, 1, NOW(), NOW());
INSERT INTO translations (namespace, key, locale, value, is_reviewed, version, created_at, updated_at) VALUES ('ui', 'landingPage.seoSection.article2.title', 'ja', '一人旅の方のためのつながりプラットフォーム', false, 1, NOW(), NOW());
INSERT INTO translations (namespace, key, locale, value, is_reviewed, version, created_at, updated_at) VALUES ('ui', 'landingPage.seoSection.article2.title', 'ko', '혼자 여행하는 분들을 위한 연결 플랫폼', false, 1, NOW(), NOW());
INSERT INTO translations (namespace, key, locale, value, is_reviewed, version, created_at, updated_at) VALUES ('ui', 'landingPage.seoSection.article2.title', 'zh', '为独行旅者打造的社交平台', false, 1, NOW(), NOW());
INSERT INTO translations (namespace, key, locale, value, is_reviewed, version, created_at, updated_at) VALUES ('ui', 'landingPage.seoSection.article3.desc', 'en', 'No one knows your city better than you. Become a local guide on Tourgether, offer unique experiences to travelers, and earn income. Register various services like food tours, photography services, shopping companions, and language interpretation.', false, 1, NOW(), NOW());
INSERT INTO translations (namespace, key, locale, value, is_reviewed, version, created_at, updated_at) VALUES ('ui', 'landingPage.seoSection.article3.desc', 'es', 'Nadie conoce tu ciudad mejor que tú. Conviértete en guía local en Tourgether, ofrece experiencias únicas a los viajeros y genera ingresos. Registra diversos servicios como tours gastronómicos, servicios de fotografía, acompañamiento de compras e interpretación de idiomas.', false, 1, NOW(), NOW());
INSERT INTO translations (namespace, key, locale, value, is_reviewed, version, created_at, updated_at) VALUES ('ui', 'landingPage.seoSection.article3.desc', 'fr', 'Personne ne connaît votre ville mieux que vous. Devenez guide local sur Tourgether, offrez des expériences uniques aux voyageurs et gagnez de l''argent. Enregistrez divers services comme des tours gastronomiques, des services photo, l''accompagnement shopping et l''interprétation linguistique.', false, 1, NOW(), NOW());
INSERT INTO translations (namespace, key, locale, value, is_reviewed, version, created_at, updated_at) VALUES ('ui', 'landingPage.seoSection.article3.desc', 'ja', 'あなたの街を一番よく知っているのはあなた自身です。Tourgetherでローカルガイドになって、旅行者に特別な体験を提供し、収入を得ましょう。グルメツアー、写真撮影サービス、ショッピング同行、言語通訳など、様々なサービスを登録できます。', false, 1, NOW(), NOW());
INSERT INTO translations (namespace, key, locale, value, is_reviewed, version, created_at, updated_at) VALUES ('ui', 'landingPage.seoSection.article3.desc', 'ko', '당신의 도시를 가장 잘 아는 사람은 바로 당신입니다. Tourgether에서 로컬 가이드가 되어 여행자들에게 특별한 경험을 제공하고 수익을 창출하세요. 맛집 투어, 사진 촬영 서비스, 쇼핑 동행, 언어 통역 등 다양한 서비스를 등록할 수 있습니다.', false, 1, NOW(), NOW());
INSERT INTO translations (namespace, key, locale, value, is_reviewed, version, created_at, updated_at) VALUES ('ui', 'landingPage.seoSection.article3.desc', 'zh', '没有人比您更了解您的城市。在Tourgether成为当地导游，为旅行者提供独特体验并获得收入。可以注册美食游、摄影服务、陪同购物、语言翻译等各种服务。', false, 1, NOW(), NOW());
INSERT INTO translations (namespace, key, locale, value, is_reviewed, version, created_at, updated_at) VALUES ('ui', 'landingPage.seoSection.article3.title', 'en', 'A sharing economy where locals can earn', false, 1, NOW(), NOW());
INSERT INTO translations (namespace, key, locale, value, is_reviewed, version, created_at, updated_at) VALUES ('ui', 'landingPage.seoSection.article3.title', 'es', 'Una economía colaborativa donde los locales pueden ganar', false, 1, NOW(), NOW());
INSERT INTO translations (namespace, key, locale, value, is_reviewed, version, created_at, updated_at) VALUES ('ui', 'landingPage.seoSection.article3.title', 'fr', 'Une économie de partage où les locaux peuvent gagner', false, 1, NOW(), NOW());
INSERT INTO translations (namespace, key, locale, value, is_reviewed, version, created_at, updated_at) VALUES ('ui', 'landingPage.seoSection.article3.title', 'ja', '地元の人も収入を得られるシェアリングエコノミー', false, 1, NOW(), NOW());
INSERT INTO translations (namespace, key, locale, value, is_reviewed, version, created_at, updated_at) VALUES ('ui', 'landingPage.seoSection.article3.title', 'ko', '현지인도 수익을 올릴 수 있는 공유경제', false, 1, NOW(), NOW());
INSERT INTO translations (namespace, key, locale, value, is_reviewed, version, created_at, updated_at) VALUES ('ui', 'landingPage.seoSection.article3.title', 'zh', '当地人也能赚钱的共享经济', false, 1, NOW(), NOW());
INSERT INTO translations (namespace, key, locale, value, is_reviewed, version, created_at, updated_at) VALUES ('ui', 'landingPage.seoSection.article4.desc', 'en', 'Trade with confidence using our escrow-based payment system. Funds are securely held until service completion, and our dispute resolution system protects both parties. Find trustworthy partners easily through reviews and verified host badges.', false, 1, NOW(), NOW());
INSERT INTO translations (namespace, key, locale, value, is_reviewed, version, created_at, updated_at) VALUES ('ui', 'landingPage.seoSection.article4.desc', 'es', 'Opera con confianza usando nuestro sistema de pago con custodia. Los fondos se mantienen seguros hasta que se complete el servicio, y nuestro sistema de resolución de disputas protege a ambas partes. Encuentra socios confiables fácilmente a través de reseñas y distintivos de anfitriones verificados.', false, 1, NOW(), NOW());
INSERT INTO translations (namespace, key, locale, value, is_reviewed, version, created_at, updated_at) VALUES ('ui', 'landingPage.seoSection.article4.desc', 'fr', 'Effectuez vos transactions en toute confiance grâce à notre système de paiement séquestre. Les fonds sont conservés en sécurité jusqu''à la fin du service, et notre système de résolution des litiges protège les deux parties. Trouvez facilement des partenaires fiables grâce aux avis et aux badges d''hôtes vérifiés.', false, 1, NOW(), NOW());
INSERT INTO translations (namespace, key, locale, value, is_reviewed, version, created_at, updated_at) VALUES ('ui', 'landingPage.seoSection.article4.desc', 'ja', 'エスクロー基盤の決済システムで安心して取引してください。サービス完了まで代金は安全に保管され、問題発生時は紛争解決システムが双方を保護します。レビューシステムと認証済みホストバッジで信頼できる相手を簡単に見つけられます。', false, 1, NOW(), NOW());
INSERT INTO translations (namespace, key, locale, value, is_reviewed, version, created_at, updated_at) VALUES ('ui', 'landingPage.seoSection.article4.desc', 'ko', '에스크로 기반 결제 시스템으로 안심하고 거래하세요. 서비스가 완료되기 전까지 대금은 안전하게 보관되며, 문제 발생 시 분쟁 해결 시스템이 양측을 보호합니다. 리뷰 시스템과 인증된 호스트 배지로 신뢰할 수 있는 상대를 쉽게 찾을 수 있습니다.', false, 1, NOW(), NOW());
INSERT INTO translations (namespace, key, locale, value, is_reviewed, version, created_at, updated_at) VALUES ('ui', 'landingPage.seoSection.article4.desc', 'zh', '通过托管支付系统安心交易。服务完成前资金安全保管，如有问题，争议解决系统保护双方。通过评价系统和认证徽章轻松找到可信赖的对象。', false, 1, NOW(), NOW());
INSERT INTO translations (namespace, key, locale, value, is_reviewed, version, created_at, updated_at) VALUES ('ui', 'landingPage.seoSection.article4.title', 'en', 'Safe P2P transaction system', false, 1, NOW(), NOW());
INSERT INTO translations (namespace, key, locale, value, is_reviewed, version, created_at, updated_at) VALUES ('ui', 'landingPage.seoSection.article4.title', 'es', 'Sistema de transacción P2P seguro', false, 1, NOW(), NOW());
INSERT INTO translations (namespace, key, locale, value, is_reviewed, version, created_at, updated_at) VALUES ('ui', 'landingPage.seoSection.article4.title', 'fr', 'Système de transaction P2P sécurisé', false, 1, NOW(), NOW());
INSERT INTO translations (namespace, key, locale, value, is_reviewed, version, created_at, updated_at) VALUES ('ui', 'landingPage.seoSection.article4.title', 'ja', '安全なP2P取引システム', false, 1, NOW(), NOW());
INSERT INTO translations (namespace, key, locale, value, is_reviewed, version, created_at, updated_at) VALUES ('ui', 'landingPage.seoSection.article4.title', 'ko', '안전한 P2P 거래 시스템', false, 1, NOW(), NOW());
INSERT INTO translations (namespace, key, locale, value, is_reviewed, version, created_at, updated_at) VALUES ('ui', 'landingPage.seoSection.article4.title', 'zh', '安全的P2P交易系统', false, 1, NOW(), NOW());
INSERT INTO translations (namespace, key, locale, value, is_reviewed, version, created_at, updated_at) VALUES ('ui', 'landingPage.seoSection.article5.desc', 'en', 'Share your travel moments with photos on the feed and visualize your journey on a map-based timeline. Our AI-powered CineMap feature analyzes photo location data to automatically create cinematic travel storyboards. Easily look back on your memories even after your trip.', false, 1, NOW(), NOW());
INSERT INTO translations (namespace, key, locale, value, is_reviewed, version, created_at, updated_at) VALUES ('ui', 'landingPage.seoSection.article5.desc', 'es', 'Comparte tus momentos de viaje con fotos en el feed y visualiza tu recorrido en una línea de tiempo basada en mapas. Nuestra función CineMap impulsada por IA analiza los datos de ubicación de las fotos para crear automáticamente storyboards de viaje cinematográficos.', false, 1, NOW(), NOW());
INSERT INTO translations (namespace, key, locale, value, is_reviewed, version, created_at, updated_at) VALUES ('ui', 'landingPage.seoSection.article5.desc', 'fr', 'Partagez vos moments de voyage avec des photos sur le fil et visualisez votre parcours sur une timeline basée sur une carte. Notre fonction CineMap alimentée par l''IA analyse les données de localisation des photos pour créer automatiquement des storyboards de voyage cinématographiques.', false, 1, NOW(), NOW());
INSERT INTO translations (namespace, key, locale, value, is_reviewed, version, created_at, updated_at) VALUES ('ui', 'landingPage.seoSection.article5.desc', 'ja', '写真と一緒に旅の瞬間をフィードで共有し、地図ベースのタイムラインで旅程を可視化しましょう。AI基盤のCineMap機能は写真の位置情報を分析して、映画のような旅行ストーリーボードを自動生成します。旅行後も思い出を簡単に振り返ることができます。', false, 1, NOW(), NOW());
INSERT INTO translations (namespace, key, locale, value, is_reviewed, version, created_at, updated_at) VALUES ('ui', 'landingPage.seoSection.article5.desc', 'ko', '사진과 함께 여행 순간을 피드에 공유하고, 지도 기반 타임라인으로 여정을 시각화하세요. AI 기반 CineMap 기능은 사진의 위치 정보를 분석해 영화 같은 여행 스토리보드를 자동으로 생성합니다. 여행 후에도 추억을 쉽게 되돌아볼 수 있습니다.', false, 1, NOW(), NOW());
INSERT INTO translations (namespace, key, locale, value, is_reviewed, version, created_at, updated_at) VALUES ('ui', 'landingPage.seoSection.article5.desc', 'zh', '在动态中分享带照片的旅行瞬间，用地图时间轴可视化您的旅程。AI驱动的CineMap功能分析照片位置信息，自动生成电影般的旅行故事板。旅行结束后也能轻松回顾美好回忆。', false, 1, NOW(), NOW());
INSERT INTO translations (namespace, key, locale, value, is_reviewed, version, created_at, updated_at) VALUES ('ui', 'landingPage.seoSection.article5.title', 'en', 'Beautifully preserve your travel memories', false, 1, NOW(), NOW());
INSERT INTO translations (namespace, key, locale, value, is_reviewed, version, created_at, updated_at) VALUES ('ui', 'landingPage.seoSection.article5.title', 'es', 'Preserva hermosamente tus recuerdos de viaje', false, 1, NOW(), NOW());
INSERT INTO translations (namespace, key, locale, value, is_reviewed, version, created_at, updated_at) VALUES ('ui', 'landingPage.seoSection.article5.title', 'fr', 'Préservez magnifiquement vos souvenirs de voyage', false, 1, NOW(), NOW());
INSERT INTO translations (namespace, key, locale, value, is_reviewed, version, created_at, updated_at) VALUES ('ui', 'landingPage.seoSection.article5.title', 'ja', '旅の記録を美しく残しましょう', false, 1, NOW(), NOW());
INSERT INTO translations (namespace, key, locale, value, is_reviewed, version, created_at, updated_at) VALUES ('ui', 'landingPage.seoSection.article5.title', 'ko', '여행 기록을 아름답게 남기세요', false, 1, NOW(), NOW());
INSERT INTO translations (namespace, key, locale, value, is_reviewed, version, created_at, updated_at) VALUES ('ui', 'landingPage.seoSection.article5.title', 'zh', '精美记录您的旅行回忆', false, 1, NOW(), NOW());
INSERT INTO translations (namespace, key, locale, value, is_reviewed, version, created_at, updated_at) VALUES ('ui', 'landingPage.seoSection.subtitle', 'en', 'A new way to rediscover the essence of travel', false, 1, NOW(), NOW());
INSERT INTO translations (namespace, key, locale, value, is_reviewed, version, created_at, updated_at) VALUES ('ui', 'landingPage.seoSection.subtitle', 'es', 'Una nueva forma de redescubrir la esencia del viaje', false, 1, NOW(), NOW());
INSERT INTO translations (namespace, key, locale, value, is_reviewed, version, created_at, updated_at) VALUES ('ui', 'landingPage.seoSection.subtitle', 'fr', 'Une nouvelle façon de redécouvrir l''essence du voyage', false, 1, NOW(), NOW());
INSERT INTO translations (namespace, key, locale, value, is_reviewed, version, created_at, updated_at) VALUES ('ui', 'landingPage.seoSection.subtitle', 'ja', '旅の本質を取り戻す新しい方法', false, 1, NOW(), NOW());
INSERT INTO translations (namespace, key, locale, value, is_reviewed, version, created_at, updated_at) VALUES ('ui', 'landingPage.seoSection.subtitle', 'ko', '여행의 본질을 되찾는 새로운 방법', false, 1, NOW(), NOW());
INSERT INTO translations (namespace, key, locale, value, is_reviewed, version, created_at, updated_at) VALUES ('ui', 'landingPage.seoSection.subtitle', 'zh', '找回旅行本质的新方式', false, 1, NOW(), NOW());
